      const frX = (Math.random() - 0.5) * w * 0.8;
      const frZ = (Math.random() - 0.5) * d * 0.8;
      frost.position.set(frX, getTerrainHeight(frX, frZ, 1.4) + 0.02, frZ);
      mctx.scene.add(frost);
