      aPanel.position.set((Math.random() - 0.5) * w * 0.95, aH / 2 + 6, (Math.random() - 0.5) * d * 0.95);
      aPanel.rotation.y = Math.random() * Math.PI;
      aPanel.rotation.x = (Math.random() - 0.5) * 0.3;
      mctx.scene.add(aPanel);
