      const fpX = (Math.random() - 0.5) * w * 0.8, fpZ = (Math.random() - 0.5) * d * 0.8;
      fpGrp.position.set(fpX, getTerrainHeight(fpX, fpZ, 1.4), fpZ);
      mctx.scene.add(fpGrp);
